<?php
if ( ! defined( 'ABSPATH' ) ) { exit; }
final class EBM_Shortcodes {
	public static function init(){add_shortcode('ebm_booking_form',array(__CLASS__,'booking_form'));add_shortcode('ebm_my_bookings',array(__CLASS__,'my_bookings'));add_action('wp_enqueue_scripts',array(__CLASS__,'assets'));}
	public static function assets(){wp_register_style('ebm-frontend',EBM_URL.'assets/css/frontend.css',array(),EBM_VERSION);wp_register_script('ebm-frontend',EBM_URL.'assets/js/frontend.js',array(),EBM_VERSION,true);wp_localize_script('ebm-frontend','EBM_DATA',array('restUrl'=>esc_url_raw(rest_url('ebm/v1/')),'nonce'=>wp_create_nonce('wp_rest'),'currency'=>'£','i18n'=>array('loading'=>__('Loading...','electrical-booking-manager'),'error'=>__('Something went wrong.','electrical-booking-manager'))));}
	public static function booking_form(){wp_enqueue_style('ebm-frontend');wp_enqueue_script('ebm-frontend');ob_start();?><div class="ebm-booking" data-ebm-booking><div class="ebm-progress"><span class="is-active">1</span><span>2</span><span>3</span><span>4</span><span>5</span></div><div class="ebm-alert" role="alert" hidden></div><section class="ebm-step is-active" data-step="1"><h2><?php esc_html_e('Choose the job','electrical-booking-manager'); ?></h2><div class="ebm-jobs"></div></section><section class="ebm-step" data-step="2"><h2><?php esc_html_e('Choose add-ons','electrical-booking-manager'); ?></h2><p><?php esc_html_e('Prices are hidden until the final step.','electrical-booking-manager'); ?></p><div class="ebm-addons"></div><button type="button" class="ebm-btn" data-next><?php esc_html_e('Continue','electrical-booking-manager'); ?></button></section><section class="ebm-step" data-step="3"><h2><?php esc_html_e('Choose date and time','electrical-booking-manager'); ?></h2><label><?php esc_html_e('Start date','electrical-booking-manager'); ?><input type="date" class="ebm-date"></label><div class="ebm-slots"></div></section><section class="ebm-step" data-step="4"><h2><?php esc_html_e('Your details','electrical-booking-manager'); ?></h2><label><?php esc_html_e('Name','electrical-booking-manager'); ?><input type="text" class="ebm-name" autocomplete="name"></label><label><?php esc_html_e('Email','electrical-booking-manager'); ?><input type="email" class="ebm-email" autocomplete="email"></label><label><?php esc_html_e('Phone','electrical-booking-manager'); ?><input type="tel" class="ebm-phone" autocomplete="tel"></label><label><?php esc_html_e('Service address','electrical-booking-manager'); ?><textarea class="ebm-address" rows="4"></textarea></label><label class="ebm-check"><input type="checkbox" class="ebm-privacy"> <?php esc_html_e('I accept the privacy policy.','electrical-booking-manager'); ?></label><button type="button" class="ebm-btn" data-next><?php esc_html_e('Continue','electrical-booking-manager'); ?></button></section><section class="ebm-step" data-step="5"><h2><?php esc_html_e('Confirm and pay deposit','electrical-booking-manager'); ?></h2><div class="ebm-summary"></div><button type="button" class="ebm-btn ebm-confirm"><?php esc_html_e('Confirm booking and pay deposit','electrical-booking-manager'); ?></button></section></div><?php return ob_get_clean();}
	public static function my_bookings(){global $wpdb;$token=sanitize_text_field(wp_unslash($_GET['ebm_booking']??'')); if(!$token){return '<p>'.esc_html__('Use the secure booking link from your confirmation email to view your booking.','electrical-booking-manager').'</p>';}$b=$wpdb->get_row($wpdb->prepare('SELECT b.*,j.title job_title FROM '.EBM_Helpers::table('bookings').' b INNER JOIN '.EBM_Helpers::table('jobs').' j ON j.id=b.job_id WHERE public_token=%s',$token)); if(!$b){return '<p>'.esc_html__('Booking not found.','electrical-booking-manager').'</p>';} return '<div class="ebm-my-booking"><h2>'.esc_html($b->job_title).'</h2><p><strong>'.esc_html__('Status:','electrical-booking-manager').'</strong> '.esc_html($b->status).'</p><p><strong>'.esc_html__('Start:','electrical-booking-manager').'</strong> '.esc_html(mysql2date(get_option('date_format').' '.get_option('time_format'),$b->start_at)).'</p><p><strong>'.esc_html__('Total:','electrical-booking-manager').'</strong> '.esc_html(EBM_Helpers::money($b->total_amount)).'</p></div>';}
}
